"use client";

import { useState } from "react";
import AdvisorForm from "./components/AdvisorForm";
import ResultsView from "./components/ResultsView";
import LoadingState from "./components/LoadingState";

export default function Home() {
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<any>(null);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (data: { prompt: string; developer_level: string; budget: string }) => {
    setIsLoading(true);
    setError(null);
    setResults(null);

    try {
      const res = await fetch("/api/advise", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });

      if (!res.ok) {
        const err = await res.json().catch(() => ({ error: "Error del servidor" }));
        throw new Error(err.error || `Error ${res.status}`);
      }

      const json = await res.json();
      setResults(json);
    } catch (err: any) {
      setError(err.message || "Error inesperado");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <main className="min-h-screen">
      {/* Hero */}
      <div className="max-w-3xl mx-auto px-4 pt-16 pb-10 text-center">
        <h1 className="text-4xl sm:text-5xl font-bold tracking-tight mb-4">
          <span className="gradient-text">AI Stack</span> Advisor
        </h1>
        <p className="text-[var(--text-muted)] text-lg max-w-xl mx-auto">
          Encuentra el stack de IA optimo para tu proyecto. Respaldado por benchmarks, papers academicos y datos reales.
        </p>
      </div>

      {/* Form */}
      <div className="max-w-2xl mx-auto px-4 pb-8">
        <AdvisorForm onSubmit={handleSubmit} isLoading={isLoading} />
      </div>

      {/* Error */}
      {error && (
        <div className="max-w-2xl mx-auto px-4 pb-8">
          <div className="bg-red-900/20 border border-red-800/40 rounded-lg p-4 text-sm text-red-400">
            {error}
          </div>
        </div>
      )}

      {/* Loading */}
      {isLoading && (
        <div className="max-w-3xl mx-auto px-4 pb-16">
          <LoadingState />
        </div>
      )}

      {/* Results */}
      {results && !isLoading && (
        <div className="max-w-4xl mx-auto px-4 pb-16">
          <ResultsView data={results} />
        </div>
      )}

      {/* Footer */}
      <footer className="border-t border-[var(--border)] py-6 text-center text-xs text-[var(--text-muted)]">
        AI Stack Advisor — Datos de SWE-bench, Aider, BigCodeBench, Arena y 27+ papers academicos
      </footer>
    </main>
  );
}
