"use client";

interface ArchNode {
  id: string;
  tool_name: string;
  capability_id: string;
  capability_name: string;
  phase: number;
  category: string;
}

interface ArchEdge {
  from: string;
  to: string;
  label: string;
  type: "data_flow" | "feedback";
}

interface ArchitectureDiagramProps {
  diagram: { nodes: ArchNode[]; edges: ArchEdge[] } | undefined;
}

const CATEGORY_COLORS: Record<string, { bg: string; border: string; text: string }> = {
  planning: { bg: "bg-blue-950/50", border: "border-blue-800/40", text: "text-blue-400" },
  design: { bg: "bg-purple-950/50", border: "border-purple-800/40", text: "text-purple-400" },
  implementation: { bg: "bg-green-950/50", border: "border-green-800/40", text: "text-green-400" },
  testing: { bg: "bg-yellow-950/50", border: "border-yellow-800/40", text: "text-yellow-400" },
  deployment: { bg: "bg-orange-950/50", border: "border-orange-800/40", text: "text-orange-400" },
  documentation: { bg: "bg-gray-900/50", border: "border-gray-700/40", text: "text-gray-400" },
};

const CATEGORY_LABELS: Record<string, string> = {
  planning: "Planificacion",
  design: "Diseno",
  implementation: "Implementacion",
  testing: "Testing",
  deployment: "Deploy",
  documentation: "Docs",
};

export default function ArchitectureDiagram({ diagram }: ArchitectureDiagramProps) {
  if (!diagram || diagram.nodes.length === 0) return null;

  // Group nodes by category for layered layout
  const categories = ["planning", "design", "implementation", "testing", "deployment", "documentation"];
  const grouped: Record<string, ArchNode[]> = {};
  for (const cat of categories) {
    const catNodes = diagram.nodes.filter((n) => n.category === cat);
    if (catNodes.length > 0) grouped[cat] = catNodes;
  }

  const activeCategories = Object.keys(grouped);

  return (
    <div className="space-y-4">
      <h2 className="text-xl font-bold">Arquitectura del Stack</h2>

      {/* Layered diagram */}
      <div className="bg-[var(--bg-card)] border border-[var(--border)] rounded-lg p-6 space-y-4">
        {activeCategories.map((cat, catIndex) => {
          const colors = CATEGORY_COLORS[cat] || CATEGORY_COLORS.implementation;
          const nodes = grouped[cat];

          return (
            <div key={cat}>
              {/* Category label */}
              <div className={`text-[10px] uppercase tracking-widest font-medium ${colors.text} mb-2`}>
                {CATEGORY_LABELS[cat] || cat}
              </div>

              {/* Nodes in this layer */}
              <div className="flex flex-wrap gap-3">
                {nodes.map((node) => {
                  // Find edges from this node
                  const outEdges = diagram.edges.filter((e) => e.from === node.id);
                  const inEdges = diagram.edges.filter((e) => e.to === node.id);

                  return (
                    <div
                      key={`${node.id}-${node.capability_id}`}
                      className={`${colors.bg} ${colors.border} border rounded-lg p-3 flex-1 min-w-[200px] max-w-sm`}
                    >
                      <div className="flex items-center gap-2 mb-1">
                        <div className={`w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-bold text-white ${
                          cat === "planning" ? "bg-blue-600" :
                          cat === "design" ? "bg-purple-600" :
                          cat === "implementation" ? "bg-green-600" :
                          cat === "testing" ? "bg-yellow-600" :
                          cat === "deployment" ? "bg-orange-600" :
                          "bg-gray-600"
                        }`}>
                          {node.phase}
                        </div>
                        <div className="text-sm font-semibold text-[var(--text-primary)]">{node.tool_name}</div>
                      </div>
                      <div className="text-[10px] text-[var(--text-muted)] pl-8">{node.capability_name}</div>

                      {/* Outgoing connections */}
                      {outEdges.length > 0 && (
                        <div className="mt-2 pl-8 flex flex-wrap gap-1">
                          {outEdges.map((edge, ei) => {
                            const targetNode = diagram.nodes.find((n) => n.id === edge.to);
                            return (
                              <span
                                key={ei}
                                className={`inline-flex items-center gap-1 text-[9px] px-1.5 py-0.5 rounded-full ${
                                  edge.type === "feedback"
                                    ? "bg-yellow-900/30 text-yellow-500 border border-yellow-800/30"
                                    : "bg-[var(--bg-secondary)] text-[var(--text-muted)] border border-[var(--border)]"
                                }`}
                              >
                                {edge.label} → {targetNode?.tool_name?.split(" ")[0] || edge.to}
                              </span>
                            );
                          })}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>

              {/* Arrow between categories */}
              {catIndex < activeCategories.length - 1 && (
                <div className="flex justify-center py-1">
                  <svg width="12" height="16" viewBox="0 0 12 16" fill="none" className="text-[var(--border)]">
                    <path d="M6 0v12" stroke="currentColor" strokeWidth="1" />
                    <path d="M6 16L2 10h8L6 16z" fill="currentColor" />
                  </svg>
                </div>
              )}
            </div>
          );
        })}

        {/* Legend */}
        <div className="flex flex-wrap gap-4 pt-3 border-t border-[var(--border)]">
          <div className="flex items-center gap-1.5 text-[10px] text-[var(--text-muted)]">
            <div className="w-4 h-0.5 bg-[var(--border)]" />
            <span>Data flow</span>
          </div>
          <div className="flex items-center gap-1.5 text-[10px] text-yellow-500">
            <div className="w-4 h-0.5 border-t border-dashed border-yellow-500" />
            <span>Feedback loop</span>
          </div>
          {activeCategories.map((cat) => {
            const colors = CATEGORY_COLORS[cat];
            return (
              <div key={cat} className="flex items-center gap-1.5 text-[10px]">
                <div className={`w-2.5 h-2.5 rounded-full ${
                  cat === "planning" ? "bg-blue-600" :
                  cat === "design" ? "bg-purple-600" :
                  cat === "implementation" ? "bg-green-600" :
                  cat === "testing" ? "bg-yellow-600" :
                  cat === "deployment" ? "bg-orange-600" :
                  "bg-gray-600"
                }`} />
                <span className={colors?.text}>{CATEGORY_LABELS[cat]}</span>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
