"use client";

import { useState } from "react";

interface JustificationProps {
  recommendations: any[];
}

// --- Layer 1: Score Circle (Lighthouse-style) ---

function ScoreCircle({ score, size = 48 }: { score: number; size?: number }) {
  const display = (score * 10).toFixed(1);
  const pct = score * 100;
  const radius = (size - 6) / 2;
  const circumference = 2 * Math.PI * radius;
  const offset = circumference - (pct / 100) * circumference;
  const color = score >= 0.7 ? "#22c55e" : score >= 0.5 ? "#eab308" : "#ef4444";

  return (
    <div className="relative" style={{ width: size, height: size }}>
      <svg width={size} height={size} className="-rotate-90">
        <circle
          cx={size / 2} cy={size / 2} r={radius}
          fill="none" stroke="var(--bg-secondary)" strokeWidth={3}
        />
        <circle
          cx={size / 2} cy={size / 2} r={radius}
          fill="none" stroke={color} strokeWidth={3}
          strokeDasharray={circumference}
          strokeDashoffset={offset}
          strokeLinecap="round"
        />
      </svg>
      <div className="absolute inset-0 flex items-center justify-center">
        <span className="text-xs font-mono font-bold" style={{ color }}>{display}</span>
      </div>
    </div>
  );
}

// --- Mini gauge for score breakdown ---

function MiniGauge({ label, value }: { label: string; value: number }) {
  const color = value >= 0.7 ? "text-green-400" : value >= 0.5 ? "text-yellow-400" : "text-red-400";
  const bgColor = value >= 0.7 ? "bg-green-400" : value >= 0.5 ? "bg-yellow-400" : "bg-red-400";
  return (
    <div className="flex flex-col items-center gap-0.5">
      <div className="w-8 h-1 bg-[var(--bg-primary)] rounded-full overflow-hidden">
        <div className={`h-full rounded-full ${bgColor}`} style={{ width: `${value * 100}%` }} />
      </div>
      <span className={`text-[9px] font-mono ${color}`}>{(value * 10).toFixed(1)}</span>
      <span className="text-[8px] text-[var(--text-muted)] leading-tight text-center">{label}</span>
    </div>
  );
}

// --- Layer 2: Compact comparison row ---

function ComparisonTable({ h2h }: { h2h: any }) {
  if (!h2h || !h2h.benchmarks || h2h.benchmarks.length === 0) return null;

  return (
    <div className="text-[11px]">
      <div className="grid grid-cols-3 gap-0 text-[10px] text-[var(--text-muted)] mb-1">
        <span></span>
        <span className="text-center text-green-400 font-medium truncate">{h2h.winner.tool_name}</span>
        <span className="text-center truncate">{h2h.runner_up.tool_name}</span>
      </div>
      {h2h.benchmarks.map((b: any, i: number) => (
        <div key={i} className="grid grid-cols-3 gap-0 py-0.5 border-t border-[var(--border)]/50">
          <span className="text-[var(--text-muted)] text-[10px] truncate pr-1">{b.benchmark_name}</span>
          <span className="text-center font-mono font-bold text-green-400 text-[10px]">{b.winner_value}</span>
          <span className="text-center font-mono text-[var(--text-muted)] text-[10px]">{b.runner_up_value}</span>
        </div>
      ))}
    </div>
  );
}

// --- Main Component ---

export default function Justification({ recommendations }: JustificationProps) {
  const [expandedIndex, setExpandedIndex] = useState<number | null>(null);

  return (
    <div className="space-y-4">
      <h2 className="text-xl font-bold">Por que estas herramientas</h2>

      {/* All cards visible — no accordion, compact layout */}
      <div className="grid gap-3">
        {recommendations.map((rec, i) => {
          const t = rec.recommended_tool;
          const b = t.score_breakdown;
          const ej = t.enhanced_justification;
          const isExpanded = expandedIndex === i;
          const hasEvidence = (rec.evidence?.length > 0) || (rec.papers?.length > 0);

          return (
            <div
              key={i}
              className="bg-[var(--bg-card)] border border-[var(--border)] rounded-lg p-4"
            >
              {/* Row 1: Circle + Tool + Verdict + Cost — THE ONE GLANCE */}
              <div className="flex items-center gap-3">
                <ScoreCircle score={t.final_score} />

                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap">
                    <span className="font-semibold text-sm text-[var(--accent-hover)]">{t.tool.name}</span>
                    <span className="text-[10px] text-[var(--text-muted)]">{rec.capability_name}</span>
                    {ej?.cost_estimate && (
                      <span className="font-mono text-[10px] px-1.5 py-0.5 rounded bg-[var(--bg-secondary)] text-[var(--text-muted)]">
                        {ej.cost_estimate.estimated_monthly}
                      </span>
                    )}
                  </div>
                  {/* One-line verdict */}
                  <div className="text-[11px] text-[var(--text-secondary)] mt-0.5 line-clamp-1">
                    {ej?.head_to_head?.verdict || t.tool.strengths[0]}
                  </div>
                </div>

                {/* Mini gauges — score breakdown at a glance */}
                <div className="hidden sm:flex items-center gap-2 shrink-0">
                  <MiniGauge label="Quality" value={b.quality} />
                  <MiniGauge label="Fit" value={b.task_fit} />
                  <MiniGauge label="Cost" value={b.cost} />
                </div>
              </div>

              {/* Row 2: Benchmark pills inline */}
              {ej?.benchmark_citations && (
                <div className="flex flex-wrap gap-1 mt-2 ml-[60px]">
                  {ej.benchmark_citations.map((c: string, j: number) => (
                    <span
                      key={j}
                      className="px-1.5 py-0.5 bg-[var(--accent)]/10 text-[var(--accent-hover)] text-[9px] font-mono rounded border border-[var(--accent)]/15"
                    >
                      {c}
                    </span>
                  ))}
                  {ej?.trade_offs?.length > 0 && (
                    <span className="px-1.5 py-0.5 bg-yellow-900/20 text-yellow-500 text-[9px] rounded border border-yellow-800/20">
                      {ej.trade_offs.length} trade-off{ej.trade_offs.length > 1 ? "s" : ""}
                    </span>
                  )}
                </div>
              )}

              {/* Row 3: Expand for deep dive — one click */}
              <div className="mt-2 ml-[60px]">
                <button
                  onClick={() => setExpandedIndex(isExpanded ? null : i)}
                  className="text-[10px] text-[var(--text-muted)] hover:text-[var(--accent-hover)] flex items-center gap-1 transition-colors"
                >
                  <svg
                    className={`w-3 h-3 transition-transform ${isExpanded ? "rotate-90" : ""}`}
                    fill="none" stroke="currentColor" viewBox="0 0 24 24"
                  >
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                  </svg>
                  {isExpanded ? "Menos" : "Ver analisis completo"}
                  {hasEvidence && !isExpanded && (
                    <span className="text-[8px] text-[var(--text-muted)]">
                      ({(rec.evidence?.length || 0) + (rec.papers?.length || 0)} fuentes)
                    </span>
                  )}
                </button>

                {isExpanded && (
                  <div className="mt-3 space-y-3 border-t border-[var(--border)]/50 pt-3">
                    {/* Head-to-head comparison */}
                    {ej?.head_to_head && <ComparisonTable h2h={ej.head_to_head} />}

                    {/* Cost detail */}
                    {ej?.cost_estimate?.explanation && (
                      <div className="text-[10px] text-[var(--text-muted)]">
                        <span className="text-[var(--text-secondary)]">Costo:</span> {ej.cost_estimate.explanation}
                      </div>
                    )}

                    {/* Trade-offs */}
                    {ej?.trade_offs?.map((t: string, j: number) => (
                      <div key={j} className="text-[10px] text-yellow-400/70 flex items-start gap-1">
                        <span className="shrink-0">~</span>
                        <span>{t}</span>
                      </div>
                    ))}

                    {/* Fit */}
                    {ej?.fit_explanation && (
                      <div className="text-[10px] text-[var(--text-muted)]">{ej.fit_explanation}</div>
                    )}

                    {/* Evidence — compact links */}
                    {rec.evidence?.length > 0 && (
                      <div className="flex flex-wrap gap-1.5">
                        {rec.evidence.map((ev: any, j: number) => (
                          <a
                            key={j}
                            href={ev.url}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="inline-flex items-center gap-1 px-1.5 py-0.5 text-[9px] bg-[var(--bg-secondary)] text-[var(--text-muted)] hover:text-[var(--accent-hover)] rounded border border-[var(--border)] transition-colors"
                          >
                            <span className="text-[8px] opacity-60">
                              {ev.type === "technical_report" ? "RPT" : ev.type === "best_practices" ? "BP" : "DOC"}
                            </span>
                            {ev.title.length > 40 ? ev.title.slice(0, 40) + "..." : ev.title}
                          </a>
                        ))}
                      </div>
                    )}

                    {/* Papers — compact */}
                    {rec.papers?.length > 0 && (
                      <div className="flex flex-wrap gap-1.5">
                        {rec.papers.map((p: any, j: number) => (
                          <a
                            key={j}
                            href={p.url}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="inline-flex items-center gap-1 px-1.5 py-0.5 text-[9px] rounded border transition-colors hover:text-[var(--accent-hover)]"
                            style={{
                              background: p.type === "peer_reviewed" ? "rgba(34,197,94,0.08)" : "rgba(234,179,8,0.08)",
                              borderColor: p.type === "peer_reviewed" ? "rgba(34,197,94,0.15)" : "rgba(234,179,8,0.15)",
                              color: p.type === "peer_reviewed" ? "rgb(74,222,128)" : "rgb(250,204,21)",
                            }}
                          >
                            {p.type === "peer_reviewed" ? "PR" : "PP"}
                            <span className="text-[var(--text-muted)]">
                              {p.title.length > 35 ? p.title.slice(0, 35) + "..." : p.title}
                            </span>
                          </a>
                        ))}
                      </div>
                    )}
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
