"use client";

import { useState } from "react";

interface PrebuiltPromptsProps {
  recommendations: any[];
}

function CopyButton({ text }: { text: string }) {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      // Fallback for non-secure contexts
      const textarea = document.createElement("textarea");
      textarea.value = text;
      document.body.appendChild(textarea);
      textarea.select();
      document.execCommand("copy");
      document.body.removeChild(textarea);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  return (
    <button
      onClick={handleCopy}
      className={`px-3 py-1.5 text-xs rounded-md transition-colors ${
        copied
          ? "bg-green-600 text-white"
          : "bg-[var(--accent)] hover:bg-[var(--accent-hover)] text-white"
      }`}
    >
      {copied ? "Copiado!" : "Copiar"}
    </button>
  );
}

export default function PrebuiltPrompts({ recommendations }: PrebuiltPromptsProps) {
  const [expandedOutput, setExpandedOutput] = useState<number | null>(null);
  const prompts = recommendations.filter((r) => r.prebuilt_prompt);

  if (prompts.length === 0) return null;

  return (
    <div className="space-y-4">
      <h2 className="text-xl font-bold flex items-center gap-2">
        Prompts Listos para Usar
        <span className="text-xs font-normal text-[var(--text-muted)] bg-[var(--bg-secondary)] px-2 py-0.5 rounded-full">
          Copia y pega
        </span>
      </h2>

      <div className="space-y-3">
        {prompts.map((rec, i) => {
          const p = rec.prebuilt_prompt;
          return (
            <div
              key={i}
              className="bg-[var(--bg-card)] border border-[var(--border)] rounded-lg overflow-hidden"
            >
              {/* Header */}
              <div className="flex items-center justify-between px-4 py-3 border-b border-[var(--border)]">
                <div className="flex items-center gap-2 min-w-0">
                  <span className="text-sm font-semibold text-[var(--accent-hover)]">{p.tool_name}</span>
                  <span className="text-xs text-[var(--text-muted)]">— {rec.capability_name}</span>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  <span className={`px-1.5 py-0.5 text-[9px] rounded-full font-medium ${
                    p.generated_by === "ai"
                      ? "bg-[var(--accent)]/20 text-[var(--accent-hover)]"
                      : "bg-[var(--bg-secondary)] text-[var(--text-muted)]"
                  }`}>
                    {p.generated_by === "ai" ? "IA" : "Template"}
                  </span>
                  <CopyButton text={p.prompt_text} />
                </div>
              </div>

              {/* Instruction */}
              <div className="px-4 pt-3 text-xs text-[var(--text-muted)]">
                {p.instruction}
              </div>

              {/* Prompt text */}
              <div className="px-4 py-3">
                <pre className="text-xs text-[var(--text-secondary)] bg-[var(--bg-primary)] rounded-lg p-3 overflow-x-auto whitespace-pre-wrap font-mono leading-relaxed border border-[var(--border)]">
                  {p.prompt_text}
                </pre>
              </div>

              {/* Expected output - collapsible */}
              <div className="px-4 pb-3">
                <button
                  onClick={() => setExpandedOutput(expandedOutput === i ? null : i)}
                  className="text-[10px] text-[var(--text-muted)] hover:text-[var(--text-secondary)] flex items-center gap-1"
                >
                  <svg
                    className={`w-3 h-3 transition-transform ${expandedOutput === i ? "rotate-90" : ""}`}
                    fill="none" stroke="currentColor" viewBox="0 0 24 24"
                  >
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" />
                  </svg>
                  Output esperado
                </button>
                {expandedOutput === i && (
                  <div className="mt-1.5 text-xs text-[var(--text-muted)] bg-[var(--bg-secondary)] rounded p-2">
                    {p.expected_output}
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
