interface StackTableProps {
  recommendations: any[];
}

function ScoreBadge({ score }: { score: number }) {
  const display = (score * 10).toFixed(1);
  const colorClass = score >= 0.7 ? "score-high" : score >= 0.5 ? "score-mid" : "score-low";
  return <span className={`font-mono font-bold ${colorClass}`}>{display}</span>;
}

export default function StackTable({ recommendations }: StackTableProps) {
  return (
    <div className="space-y-4">
      <h2 className="text-xl font-bold">Stack Recomendado</h2>

      {/* Desktop table */}
      <div className="hidden md:block overflow-x-auto">
        <table className="w-full text-sm">
          <thead>
            <tr className="border-b border-[var(--border)]">
              <th className="text-left py-3 px-4 text-[var(--text-muted)] font-medium">Fase</th>
              <th className="text-left py-3 px-4 text-[var(--text-muted)] font-medium">Capacidad</th>
              <th className="text-left py-3 px-4 text-[var(--text-muted)] font-medium">Herramienta</th>
              <th className="text-center py-3 px-4 text-[var(--text-muted)] font-medium">Score</th>
              <th className="text-left py-3 px-4 text-[var(--text-muted)] font-medium">Por que</th>
            </tr>
          </thead>
          <tbody>
            {recommendations.map((rec, i) => (
              <tr key={i} className="border-b border-[var(--border)] hover:bg-[var(--bg-secondary)]">
                <td className="py-3 px-4 font-mono text-[var(--text-muted)]">{rec.phase}</td>
                <td className="py-3 px-4">{rec.capability_name}</td>
                <td className="py-3 px-4 font-semibold text-[var(--accent-hover)]">
                  {rec.recommended_tool.tool.name}
                </td>
                <td className="py-3 px-4 text-center">
                  <ScoreBadge score={rec.recommended_tool.final_score} />
                </td>
                <td className="py-3 px-4 text-[var(--text-secondary)] text-xs">
                  {rec.recommended_tool.tool.strengths[0]}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Mobile cards */}
      <div className="md:hidden space-y-3">
        {recommendations.map((rec, i) => (
          <div key={i} className="bg-[var(--bg-card)] border border-[var(--border)] rounded-lg p-4 space-y-2">
            <div className="flex justify-between items-start">
              <div>
                <div className="text-xs text-[var(--text-muted)]">Fase {rec.phase} — {rec.capability_name}</div>
                <div className="font-semibold text-[var(--accent-hover)] mt-1">{rec.recommended_tool.tool.name}</div>
              </div>
              <ScoreBadge score={rec.recommended_tool.final_score} />
            </div>
            <div className="text-xs text-[var(--text-secondary)]">{rec.recommended_tool.tool.strengths[0]}</div>
          </div>
        ))}
      </div>

      {/* Alternatives */}
      {recommendations.some((r) => r.alternatives?.length > 0) && (
        <div className="mt-4">
          <h3 className="text-sm font-medium text-[var(--text-muted)] mb-2">Alternativas</h3>
          <div className="space-y-1 text-sm">
            {recommendations.map((rec, i) =>
              rec.alternatives?.[0] ? (
                <div key={i} className="text-[var(--text-secondary)]">
                  <span className="text-[var(--text-muted)]">{rec.capability_name}:</span>{" "}
                  {rec.alternatives[0].tool.name}{" "}
                  <span className="font-mono text-xs">({(rec.alternatives[0].final_score * 10).toFixed(1)})</span>
                </div>
              ) : null
            )}
          </div>
        </div>
      )}
    </div>
  );
}
